import React from "react";
import { InputMask, type InputMaskProps } from "primereact/inputmask";
import type { IKitsInputMask } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import { useFormInputController } from "../../helpers/useFormInputController";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";

const KitsInputMask = ({ ref, ...rawProps }: IKitsInputMask) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('InputMask', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const {
        id,
        label,
        required,
        value,
        defaultValue,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        disabled,
        attached,
        helperText,
        inputSize,
        onChange,
        localProps,
        leftAddon,
        rightAddon,
        containerStyle,
        ...rest
    } = props;

    // 🔑 unified control logic (correct)
    const { value: displayValue, emitChange } =
        useFormInputController<string>({
            value,
            defaultValue,
            onChange,
        });

    const { nativeProps } = useSeparator<InputMaskProps>(rest);

    const className = `w-full ${(nativeProps as any).className ?? ""}`;

    if(attached){
        return(
            <InputMask
                ref={ref as any}
                disabled={disabled}
                value={displayValue ?? ""}
                className={className}
                width={'100%'}
                onChange={(e) => {
                    const next =
                        (e as any).value ??
                        (e as any).target?.value ??
                        "";
                    emitChange(next);
                }}
                {...nativeProps}
                {...(localProps as any)}
                style={{ borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
            />
        )
    }
    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
            inputSize={inputSize}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            <InputMask
                ref={ref as any}
                disabled={disabled}
                value={displayValue ?? ""}
                className={className}
                onChange={(e) => {
                    const next =
                        (e as any).value ??
                        (e as any).target?.value ??
                        "";
                    emitChange(next);
                }}
                {...nativeProps}
                {...(localProps as any)}
                style={{ borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
            />
        </KitsContainer>
    );
};

export default KitsInputMask;
